export default function mapAsyncLimit(items, limit, worker, strategy = 'fail-fast') {
  if (!Number.isFinite(limit) || limit < 1) throw new Error('limit must be >= 1');

  const allSettled = strategy === 'all-settled';
  const results = new Array(items.length);
  let current = 0;

  const run = async () => {
    const i = current++;
    if (i >= items.length) return;

    try {
      const val = await worker(items[i], i);
      results[i] = allSettled
        ? { status: 'fulfilled', value: val }
        : val;
    } catch (err) {
      if (!allSettled) throw err;
      results[i] = { status: 'rejected', reason: err };
    }

    return run(); // refill this slot with the next item
  };

  const k = Math.min(limit, items.length);
  const runners = Array.from({ length: k }, () => run());

  return allSettled
    ? Promise.allSettled(runners).then(() => results)
    : Promise.all(runners).then(() => results);
}
